// ─── STEP 1: Validate binary input ───────────────────────────────────────────
if (!items[0].binary || Object.keys(items[0].binary).length === 0) {
  return [{ json: {
    exifFound: false,
    exifDateTimeOriginal: null,
    exifGpsLat: null,
    exifGpsLng: null,
    fileType: 'no_binary',
    note: 'No binary data received from Download Document node',
    log: '❌ Binary is empty — Download Document node may have failed silently'
  }}];
}

const binaryKey = Object.keys(items[0].binary)[0];
const buffer = Buffer.from(items[0].binary[binaryKey].data, 'base64');
const magicHex = buffer.slice(0, 4).toString('hex');
const magicBytes = [buffer[0], buffer[1], buffer[2], buffer[3]];

// ─── STEP 2: Detect file type from magic bytes ────────────────────────────────
const isJPEG = buffer[0] === 0xFF && buffer[1] === 0xD8;
const isPNG  = buffer[0] === 0x89 && buffer[1] === 0x50 && buffer[2] === 0x4E && buffer[3] === 0x47;
const isHEIC = buffer.slice(4, 8).toString('ascii') === 'ftyp';
const isWEBP = buffer.slice(0, 4).toString('ascii') === 'RIFF' && buffer.slice(8, 12).toString('ascii') === 'WEBP';

let fileType = isJPEG ? 'JPEG' : isPNG ? 'PNG' : isHEIC ? 'HEIC' : isWEBP ? 'WEBP' : 'unknown';

const baseLog = [
  `📁 Binary field name: "${binaryKey}"`,
  `📦 Buffer size: ${buffer.length} bytes`,
  `🔢 Magic bytes: ${magicHex} → detected as ${fileType}`,
  `🔢 Raw first bytes: [${magicBytes.join(', ')}]`
];

if (!isJPEG) {
  return [{ json: {
    exifFound: false,
    exifDateTimeOriginal: null,
    exifGpsLat: null,
    exifGpsLng: null,
    fileType,
    note: `${fileType} detected — EXIF not parsed, will use message.date fallback`,
    log: baseLog.join('\n') + `\n⚠️ Not a JPEG — skipping EXIF parse, fallback to message.date`
  }}];
}

// ─── STEP 3: Parse EXIF (JPEG only) ──────────────────────────────────────────
let result = {
  exifFound: false,
  exifDateTimeOriginal: null,
  exifGpsLat: null,
  exifGpsLng: null,
  fileType: 'JPEG'
};
const logs = [...baseLog];

function readUInt16(buf, offset, le) {
  return le ? buf[offset] | (buf[offset+1]<<8) : (buf[offset]<<8) | buf[offset+1];
}
function readUInt32(buf, offset, le) {
  return le
    ? buf[offset] | (buf[offset+1]<<8) | (buf[offset+2]<<16) | (buf[offset+3]<<24)
    : (buf[offset]<<24) | (buf[offset+1]<<16) | (buf[offset+2]<<8) | buf[offset+3];
}
function readRational(buf, offset, le) {
  const num = readUInt32(buf, offset, le);
  const den = readUInt32(buf, offset+4, le);
  return den !== 0 ? num/den : 0;
}
function readString(buf, offset, length) {
  return buf.slice(offset, offset+length).toString('ascii').replace(/\0/g,'').trim();
}

try {
  let offset = 2, app1Offset = -1;
  while (offset < buffer.length - 1) {
    if (buffer[offset] === 0xFF && buffer[offset+1] === 0xE1) {
      app1Offset = offset;
      logs.push(`✅ APP1 segment found at offset ${offset}`);
      break;
    }
    if (buffer[offset] === 0xFF && buffer[offset+1] !== 0xFF) {
      const segLen = readUInt16(buffer, offset+2, false);
      offset += 2 + segLen;
    } else { offset++; }
  }

  if (app1Offset === -1) {
    logs.push('⚠️ No APP1/EXIF segment found in JPEG — photo likely has no EXIF metadata (stripped by Telegram or camera)');
    return [{ json: { ...result, note: 'No EXIF segment — using message.date fallback', log: logs.join('\n') } }];
  }

  const exifHeader = buffer.slice(app1Offset+4, app1Offset+10).toString('ascii');
  logs.push(`🔍 APP1 header: "${exifHeader}"`);

  if (!exifHeader.startsWith('Exif')) {
    logs.push('⚠️ APP1 segment exists but is not EXIF (maybe XMP)');
    return [{ json: { ...result, note: 'APP1 not EXIF — using message.date fallback', log: logs.join('\n') } }];
  }

  const exifStart = app1Offset + 10;
  const byteOrder = buffer.slice(exifStart, exifStart+2).toString('ascii');
  const le = byteOrder === 'II';
  logs.push(`🔄 Byte order: ${byteOrder} (${le ? 'little-endian' : 'big-endian'})`);

  const ifd0Offset = exifStart + readUInt32(buffer, exifStart+4, le);
  const ifd0Count = readUInt16(buffer, ifd0Offset, le);
  logs.push(`📋 IFD0 entries: ${ifd0Count}`);

  let exifIFDOffset = -1, gpsIFDOffset = -1;
  for (let i = 0; i < ifd0Count; i++) {
    const e = ifd0Offset + 2 + i*12;
    const tag = readUInt16(buffer, e, le);
    if (tag === 0x8769) { exifIFDOffset = exifStart + readUInt32(buffer, e+8, le); logs.push('✅ ExifIFD pointer found'); }
    if (tag === 0x8825) { gpsIFDOffset  = exifStart + readUInt32(buffer, e+8, le); logs.push('✅ GPS IFD pointer found'); }
  }

  if (exifIFDOffset === -1) logs.push('⚠️ No ExifIFD found — no DateTimeOriginal available');
  if (gpsIFDOffset  === -1) logs.push('⚠️ No GPS IFD found — no GPS coords in EXIF');

  if (exifIFDOffset !== -1) {
    const exifCount = readUInt16(buffer, exifIFDOffset, le);
    for (let i = 0; i < exifCount; i++) {
      const e = exifIFDOffset + 2 + i*12;
      const tag = readUInt16(buffer, e, le);
      if (tag === 0x9003) {
        const valOffset = exifStart + readUInt32(buffer, e+8, le);
        const dtStr = readString(buffer, valOffset, 19);
        logs.push(`📅 Raw EXIF DateTimeOriginal string: "${dtStr}"`);
        const [datePart, timePart] = dtStr.split(' ');
        const [y, mo, d] = datePart.split(':');
        const [h, mi, s] = timePart.split(':');
        const dt = new Date(Date.UTC(+y, +mo-1, +d, +h, +mi, +s));
        const istOffsetMs = 5.5 * 60 * 60 * 1000;
        result.exifDateTimeOriginal = Math.floor((dt.getTime() - istOffsetMs) / 1000);
        result.exifFound = true;
        logs.push(`🕐 EXIF time (parsed as IST→UTC Unix): ${result.exifDateTimeOriginal} = ${new Date(result.exifDateTimeOriginal * 1000).toISOString()}`);
      }
    }
    if (!result.exifFound) logs.push('⚠️ ExifIFD found but tag 0x9003 (DateTimeOriginal) missing');
  }

  if (gpsIFDOffset !== -1) {
    const gpsCount = readUInt16(buffer, gpsIFDOffset, le);
    let latRef='N', lngRef='E', latVal=null, lngVal=null;
    for (let i = 0; i < gpsCount; i++) {
      const e = gpsIFDOffset + 2 + i*12;
      const tag = readUInt16(buffer, e, le);
      const count = readUInt32(buffer, e+4, le);
      const valOffset = exifStart + readUInt32(buffer, e+8, le);
      if (tag === 0x0001) latRef = String.fromCharCode(buffer[e+8]);
      if (tag === 0x0003) lngRef = String.fromCharCode(buffer[e+8]);
      if (tag === 0x0002 && count === 3) {
        latVal = readRational(buffer,valOffset,le) + readRational(buffer,valOffset+8,le)/60 + readRational(buffer,valOffset+16,le)/3600;
      }
      if (tag === 0x0004 && count === 3) {
        lngVal = readRational(buffer,valOffset,le) + readRational(buffer,valOffset+8,le)/60 + readRational(buffer,valOffset+16,le)/3600;
      }
    }
    if (latVal !== null) { result.exifGpsLat = latRef==='S' ? -latVal : latVal; logs.push(`📍 EXIF GPS Lat: ${result.exifGpsLat}`); }
    if (lngVal !== null) { result.exifGpsLng = lngRef==='W' ? -lngVal : lngVal; logs.push(`📍 EXIF GPS Lng: ${result.exifGpsLng}`); }
    if (latVal === null && lngVal === null) logs.push('⚠️ GPS IFD found but no lat/lng values');
  }

} catch(e) {
  logs.push(`❌ EXIF parse error: ${e.message}`);
  result.error = e.message;
}

result.log = logs.join('\n');
return [{ json: result }];

// ─── Log Timestamps — inserted between Parse EXIF and Within 2 Minutes? ──────
const exif = items[0].json;

const locationTs  = Number($('Lookup Pending Checkin').item.json.location_timestamp);
const messageDate = Number($('Telegram Trigger').item.json.message.date);
const exifTs      = exif.exifFound ? Number(exif.exifDateTimeOriginal) : null;

const usedTs = exif.exifFound ? exifTs : messageDate;
const diff   = Math.abs(usedTs - locationTs);
const willPass = diff <= 120;

const log = [
  '─── Timestamp Comparison ───────────────────────────',
  `📍 location_timestamp (from Sheets) : ${locationTs}  → ${new Date(locationTs * 1000).toISOString()}`,
  `📨 message.date (Telegram received) : ${messageDate} → ${new Date(messageDate * 1000).toISOString()}`,
  `📸 EXIF DateTimeOriginal            : ${exifTs !== null ? exifTs + '  → ' + new Date(exifTs * 1000).toISOString() : 'N/A (no EXIF)'}`,
  '',
  `🔀 Using timestamp                  : ${exif.exifFound ? 'EXIF' : 'message.date (fallback)'}`,
  `⏱️  Difference                       : ${diff} seconds`,
  `${willPass ? '✅' : '❌'} Within 2 minutes?               : ${willPass ? 'YES — will proceed' : 'NO — will reject'}`,
  '────────────────────────────────────────────────────'
].join('\n');

return [{ json: { ...exif, locationTs, messageDate, exifTs, diff, willPass, timestamp_log: log } }];
